const parts = msg.topic.split('/');
const bikeId = parts[1];
const d = msg.payload;

msg.payload = [{
    measurement: 'bike',
    tags: { id: bikeId },
    fields: {
        lat: d.position.lat,
        lng: d.position.lng,
        current_speed: d.current_speed,
        imu_x: d.imu.x,
        imu_y: d.imu.y,
        imu_z: d.imu.z,
        imu_dx: d.imu.dx,
        imu_dy: d.imu.dy,
        imu_dz: d.imu.dz,
        battery: d.battery,
        locked: d.locked,
        status: d.status,
        current_ride: d.current_ride || ''
    }
}];

return msg;

const parts = msg.topic.split('/');
const stationId = parts[1];
const data = msg.payload;

msg.payload = [{
    measurement: 'station',
    tags: { station_id: stationId },
    fields: {
        available_slots: data.available_slots,
        bikes_docked: data.bikes_docked
    }
}];

return msg;

const data = msg.payload;
const parts = msg.topic.split('/');
const bikeId = parts[1];

const absZ = Math.abs(data.imu.z);

if (absZ > 25) {
    const ts = Date.now();
    msg.payload = [{
        measurement: 'alert',
        tags: {
            bike_id: bikeId,
            type: 'fall',
            severity: 'high'
        },
        fields: {
            alert_id: 'fall-' + bikeId + '-' + ts,
            message: 'Fall detected: |imu_z| = ' + absZ.toFixed(2) + ' m/s²'
        }
    }];
    return msg;
}

return null;

const data = msg.payload;
const parts = msg.topic.split('/');
const bikeId = parts[1];

const ZONES = global.get('parkingZones') || [];
if (ZONES.length === 0) {
    node.warn('No parking zones loaded — check parking-zones.json');
    return null;
}

function distanceMeters(lat1, lng1, lat2, lng2) {
    const R = 6371000;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLng = (lng2 - lng1) * Math.PI / 180;
    const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLng/2) * Math.sin(dLng/2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

if (data.current_speed >= 1) return null;

const lat = data.position.lat;
const lng = data.position.lng;

const insideZone = ZONES.some(zone => {
    const dist = distanceMeters(lat, lng, zone.center[0], zone.center[1]);
    return dist <= zone.radius;
});

if (!insideZone) {
    const ts = Date.now();
    msg.payload = [{
        measurement: 'alert',
        tags: {
            bike_id: bikeId,
            type: 'parking_violation',
            severity: 'medium'
        },
        fields: {
            alert_id: 'parking_violation-' + bikeId + '-' + ts,
            message: 'Bike parked outside authorized zone at ' + lat.toFixed(5) + ', ' + lng.toFixed(5)
        }
    }];
    return msg;
}

return null;

const fs = global.get('fs');
const path = '/shared/parking-zones.json';

try {
    const raw = fs.readFileSync(path, 'utf8');
    const config = JSON.parse(raw);
    global.set('parkingZones', config.zones);
    node.log('Loaded ' + config.zones.length + ' parking zones for ' + config.city);
    msg.payload = config;
    return msg;
} catch (e) {
    node.error('Failed to load parking zones: ' + e.message);
    return null;
}

const data = msg.payload;
const parts = msg.topic.split('/');
const bikeId = parts[1];

if (data.battery < 15) {
    const ts = Date.now();
    msg.payload = [{
        measurement: 'alert',
        tags: {
            bike_id: bikeId,
            type: 'low_battery',
            severity: 'low'
        },
        fields: {
            alert_id: 'low_battery-' + bikeId + '-' + ts,
            message: 'Battery low: ' + data.battery.toFixed(1) + '%'
        }
    }];
    return msg;
}

return null;
